const item = $input.first().json;
const { name, email, phone, company, service, message, date, time } = item;

function getAmsterdamOffsetMs(date) {
  const parse = s => new Date(s.replace(',', '') + ':00Z').getTime();
  const amStr = date.toLocaleString('en-CA', { timeZone: 'Europe/Amsterdam', hour12: false, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  const utcStr = date.toLocaleString('en-CA', { timeZone: 'UTC', hour12: false, year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' });
  return parse(amStr) - parse(utcStr);
}

const [year, month, day] = date.split('-').map(Number);
const [hour, minute] = time.split(':').map(Number);
const pad = n => String(n).padStart(2, '0');
const localUTC = new Date(`${year}-${pad(month)}-${pad(day)}T${pad(hour)}:${pad(minute)}:00Z`);
const offsetMs = getAmsterdamOffsetMs(localUTC);
const startUtc = new Date(localUTC.getTime() - offsetMs);
const endUtc = new Date(startUtc.getTime() + 30 * 60 * 1000);

const dutchDate = new Date(date + 'T12:00:00Z').toLocaleDateString('nl-NL', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'Europe/Amsterdam'
});
const formattedDateTime = `${dutchDate} om ${time}`;

const description = [
  `Discovery Call met ${name} van ${company}`,
  '',
  `Naam: ${name}`,
  `E-mail: ${email}`,
  `Telefoon: ${phone || 'niet opgegeven'}`,
  `Bedrijf: ${company}`,
  `Dienst: ${service}`,
  '',
  'Vraag / project:',
  message || '(geen bericht)',
].join('\n');

return [{
  json: {
    name, email, phone, company, service, message, date, time,
    startIso: startUtc.toISOString(),
    endIso: endUtc.toISOString(),
    formattedDateTime,
    description,
    eventBody: {
      summary: `Discovery Call – ${name} (${company})`,
      description,
      start: { dateTime: startUtc.toISOString(), timeZone: 'Europe/Amsterdam' },
      end: { dateTime: endUtc.toISOString(), timeZone: 'Europe/Amsterdam' },
      attendees: [{ email }],
      conferenceData: {
        createRequest: {
          requestId: `runvex-${Date.now()}`,
          conferenceSolutionKey: { type: 'hangoutsMeet' }
        }
      }
    }
  }
}];
